import { useEffect, useState } from 'react';
import { useRouter } from 'next/router';
import IconView from 'comps/curriculumViews/IconViewMini';
import UserDropdown from 'comps/UserDropdown';

export default function HomeView() {
  const router = useRouter();
  const [isLoading, setIsLoading] = useState(true);
  const [menuData, setMenuData] = useState(null);

  // Define your exact static style configuration here
  const staticConfig = {
    iconsLoc: 'konzeptes/icons',
    label: '🦉🏫📚🎓📜 Konzeptes 🦉🏫📚🎓📜',
    type: 'curriculumIcon',
    style: {
      fontSize: '0.9rem',
      maxWidth: 1300,
      margin: '0 auto',
    },
    titleStyle: {
      textDecoration: 'none',
    },
    cardStyle: {
      margin: '25px 0',
      borderRadius: 10,
      padding: 10,
      backgroundColor: '#dbf7c3',
      border: '1px solid white', // Preserving your specific border
      boxShadow: 'var(--shadow)',
    },
    iconStyle: {
      width: 200,
      height: 200,
    },
    labelStyle: {
      fontSize: '1.5rem',
    },
    smLabelStyle: {
      fontSize: '1rem',
    },
    list: [], // This will be filled by the API
  };

  useEffect(() => {
    // 1. Check Login
    const loggedIn = localStorage.getItem('isLoggedIn');
    if (loggedIn !== 'true') {
      window.location.href = '/lms-system';
      return;
    }

    // 2. Fetch API Data
    fetch('http://192.168.0.127:8080/ords/lms/v1/konzeptes/config')
      .then((res) => res.json())
      .then((data) => {
        try {
          // Parse the stringified list from the API
          const rawString = data.items[0].list;
          const parsedList = JSON.parse(rawString);

          // Merge API list with your static styles
          setMenuData({ ...staticConfig, list: parsedList });
          setIsLoading(false);
        } catch (e) {
          console.error('Error parsing API data', e);
        }
      })
      .catch((err) => console.error('Fetch error:', err));
  }, []);

  const handleBack = () => {
    router.push('/');
  };

  if (isLoading || !menuData) return null;

  return (
    <div
      style={{
        backgroundColor: 'var(--l)',
        minHeight: '100vh',
        position: 'relative',
      }}
    >
      {/* 🟢 USER DROPDOWN */}
      <UserDropdown />

      {/* 🔙 BACK BUTTON */}
      <button
        onClick={handleBack}
        style={{
          position: 'fixed',
          top: '20px',
          left: '20px',
          padding: '8px 16px',
          backgroundColor: 'white',
          border: '2px solid #2b7d10',
          borderRadius: '50px',
          fontWeight: 'bold',
          cursor: 'pointer',
          zIndex: 1000,
        }}
      >
        ← Back
      </button>

      <IconView data={menuData} />
    </div>
  );
}
